const data = $input.first().json;
const repos = (data.items || []).slice(0, 8);
const lines = repos.map((repo, i) => {
  const stars = repo.stargazers_count;
  const starsStr = stars >= 1000 ? (stars/1000).toFixed(1) + 'k' : stars;
  return (i+1) + '. [' + repo.full_name + '](https://github.com/' + repo.full_name.replace('/', '') + ')\n   ⭐ ' + starsStr + ' | 🍴 ' + repo.forks_count + ' | ' + (repo.language || 'Other') + '\n   ' + (repo.description || '无描述');
}).join('\n\n');
return [{json: {text: lines, total: repos.length, topRepo: repos[0]?.full_name, topStars: repos[0]?.stargazers_count || 0}}];

